27	std::shared_ptr<AbstractTransformerModel> AbstractTransformerModel::createGptModel(std::string inifile)
28	{
29	    INIReader reader = INIReader(inifile);
30	    if (reader.ParseError() < 0) {
31	        std::cout << "[ERROR] Can't load '" << inifile << "'\n";
32	        return nullptr;
33	    }
34	
35	    const std::string model_name = reader.Get("ft_instance_hyperparameter", "model_name");
36	    const std::string data_type  = reader.Get("ft_instance_hyperparameter", "data_type");
37	
38	    // gpt variant parameters
39	    ft::gptVariantParams gpt_variant_params{};
40	    std::string          model_variant = reader.Get(model_name, "model_variant", "gpt");
41	
42	    if (model_variant == "opt-pre") {
43	        gpt_variant_params.layernorm_eps              = 1e-5f;
44	        gpt_variant_params.layernorm_type             = ft::LayerNormType::pre_layernorm;
45	        gpt_variant_params.activation_type            = ft::ActivationType::Relu;
46	        gpt_variant_params.has_post_decoder_layernorm = false;
47	    }
48	    else if (model_variant == "opt-post") {
49	        gpt_variant_params.layernorm_eps              = 1e-5f;
50	        gpt_variant_params.layernorm_type             = ft::LayerNormType::post_layernorm;
51	        gpt_variant_params.activation_type            = ft::ActivationType::Relu;
52	        gpt_variant_params.has_post_decoder_layernorm = false;
53	    }
54	    else if (model_variant == "bloom-pre") {
55	        gpt_variant_params.layernorm_eps              = 1e-5f;
56	        gpt_variant_params.layernorm_type             = ft::LayerNormType::pre_layernorm;
57	        gpt_variant_params.activation_type            = ft::ActivationType::Gelu;
58	        gpt_variant_params.has_positional_encoding    = false;
59	        gpt_variant_params.has_pre_decoder_layernorm  = true;
60	        gpt_variant_params.has_post_decoder_layernorm = true;
61	        gpt_variant_params.use_attention_linear_bias  = true;
62	    }
63	    else if (model_variant == "bloom-post") {
64	        gpt_variant_params.layernorm_eps              = 1e-5f;
65	        gpt_variant_params.layernorm_type             = ft::LayerNormType::post_layernorm;
66	        gpt_variant_params.activation_type            = ft::ActivationType::Gelu;
67	        gpt_variant_params.has_positional_encoding    = false;
68	        gpt_variant_params.has_pre_decoder_layernorm  = true;
69	        gpt_variant_params.has_post_decoder_layernorm = true;
70	        gpt_variant_params.use_attention_linear_bias  = true;
71	    }
72	
73	    gpt_variant_params.has_adapters = reader.GetBoolean(model_name, "has_adapters", false);
74	
75	    // Prompt Learning Configurations
76	    int end_id                   = reader.GetInteger(model_name, "end_id");
77	    int prompt_learning_start_id = reader.GetInteger(model_name, "prompt_learning_start_id", end_id + 1);
78	    ft::PromptLearningType prompt_learning_type =
79	        static_cast<ft::PromptLearningType>(reader.GetInteger(model_name, "prompt_learning_type", 0));
80	
81	    std::map<std::string, std::pair<int, int>> prompt_learning_table_pair;
82	
83	    // NOTE: get prompt from configuration files
84	    const int num_tasks = reader.GetInteger(model_name, "num_tasks", 0);
85	    for (int task_name_id = 0; task_name_id < num_tasks; task_name_id++) {
86	        std::string config_task_name = model_name + "_task_" + std::to_string(task_name_id);
87	        std::string task_name        = reader.Get(config_task_name, "task_name");
88	        const int   prompt_length    = reader.GetInteger(config_task_name, "prompt_length", 0);
89	        prompt_learning_table_pair.insert({task_name, {task_name_id, prompt_length}});
90	    }
91	
92	    size_t max_seq_len = gpt_variant_params.has_positional_encoding ?
93	                             reader.GetInteger("ft_instance_hyperparameter", "max_seq_len") :
94	                             FT_SEQ_LEN_MAX;
95	
96	    if (data_type == "fp16") {
97	        return std::make_shared<ParallelGptTritonModel<half>>(
98	            max_seq_len,
99	            reader.GetInteger(model_name, "head_num"),
100	            reader.GetInteger(model_name, "size_per_head"),
101	            reader.GetInteger(model_name, "inter_size"),
102	            reader.GetInteger(model_name, "decoder_layers"),
103	            reader.GetInteger(model_name, "vocab_size"),
104	            reader.GetInteger(model_name, "start_id"),
105	            end_id,
106	            prompt_learning_start_id,
107	            prompt_learning_type,
108	            prompt_learning_table_pair,
109	            gpt_variant_params,
110	            reader.GetInteger("ft_instance_hyperparameter", "tensor_para_size"),
111	            reader.GetInteger("ft_instance_hyperparameter", "pipeline_para_size"),
112	            reader.Get("ft_instance_hyperparameter", "model_name"),
113	            reader.Get("ft_instance_hyperparameter", "model_dir"),
114	            reader.GetInteger("ft_instance_hyperparameter", "int8_mode"),
115	            reader.GetInteger("ft_instance_hyperparameter", "enable_custom_all_reduce", 0));
116	    }
117	#ifdef ENABLE_BF16
118	    else if (data_type == "bf16") {
119	        return std::make_shared<ParallelGptTritonModel<__nv_bfloat16>>(
120	            max_seq_len,
121	            reader.GetInteger(model_name, "head_num"),
122	            reader.GetInteger(model_name, "size_per_head"),
123	            reader.GetInteger(model_name, "inter_size"),
124	            reader.GetInteger(model_name, "decoder_layers"),
125	            reader.GetInteger(model_name, "vocab_size"),
126	            reader.GetInteger(model_name, "start_id"),
127	            end_id,
128	            prompt_learning_start_id,
129	            prompt_learning_type,
130	            prompt_learning_table_pair,
131	            gpt_variant_params,
132	            reader.GetInteger("ft_instance_hyperparameter", "tensor_para_size"),
133	            reader.GetInteger("ft_instance_hyperparameter", "pipeline_para_size"),
134	            reader.Get("ft_instance_hyperparameter", "model_name"),
135	            reader.Get("ft_instance_hyperparameter", "model_dir"),
136	            reader.GetInteger("ft_instance_hyperparameter", "int8_mode"),
137	            reader.GetInteger("ft_instance_hyperparameter", "enable_custom_all_reduce", 0));
138	    }
139	#endif
140	    else if (data_type == "fp32") {
141	        return std::make_shared<ParallelGptTritonModel<float>>(
142	            max_seq_len,
143	            reader.GetInteger(model_name, "head_num"),
144	            reader.GetInteger(model_name, "size_per_head"),
145	            reader.GetInteger(model_name, "inter_size"),
146	            reader.GetInteger(model_name, "decoder_layers"),
147	            reader.GetInteger(model_name, "vocab_size"),
148	            reader.GetInteger(model_name, "start_id"),
149	            end_id,
150	            prompt_learning_start_id,
151	            prompt_learning_type,
152	            prompt_learning_table_pair,
153	            gpt_variant_params,
154	            reader.GetInteger("ft_instance_hyperparameter", "tensor_para_size"),
155	            reader.GetInteger("ft_instance_hyperparameter", "pipeline_para_size"),
156	            reader.Get("ft_instance_hyperparameter", "model_name"),
157	            reader.Get("ft_instance_hyperparameter", "model_dir"),
158	            reader.GetInteger("ft_instance_hyperparameter", "int8_mode"),
159	            reader.GetInteger("ft_instance_hyperparameter", "enable_custom_all_reduce", 0));
160	    }
161	    else {
162	        FT_LOG_ERROR("Unsupported data type " + data_type);
163	        exit(-1);
164	    }
165	}
166	
167	template<typename T>
168	ParallelGptTritonModel<T>::ParallelGptTritonModel(size_t      tensor_para_size,
169	                                                  size_t      pipeline_para_size,
170	                                                  int         enable_custom_all_reduce,
171	                                                  std::string model_dir,
172	                                                  int         int8_mode):
173	    tensor_para_size_(tensor_para_size),
174	    pipeline_para_size_(pipeline_para_size),
175	    shared_weights_(std::vector<std::shared_ptr<ft::ParallelGptWeight<T>>>(ft::getDeviceCount())),
176	    enable_custom_all_reduce_(enable_custom_all_reduce),
177	    model_dir_(model_dir),
178	    int8_mode_(int8_mode)
179	{
180	    INIReader reader = INIReader(model_dir + "/config.ini");
181	    if (reader.ParseError() < 0) {
182	        FT_CHECK_WITH_INFO(false, ft::fmtstr("Can't load %s/config.ini", model_dir.c_str()));
183	    }
184	
185	    /* GPT Configuration File Example
186	    [gpt]
187	    model_name=gpt
188	    max_pos_seq_len=2048 ;for position embedding tables
189	    head_num=12
190	    size_per_head=64
191	    inter_size=3072
192	    num_layer=12
193	    layernorm_eps=1e-6 # optional for the default gpt
194	    layernorm_type=pre_layernorm # optional for the default gpt
195	    activation_type=Gelu # optional for the default gpt
196	    has_post_decoder_layernorm=1 # optional for the default gpt
197	    vocab_size=50257
198	    start_id=50256
199	    end_id=50256
200	    prompt_learning_start_id=50257
201	    prompt_learning_type=3
202	    num_tasks=3
203	
204	    [task_0]
205	    task_name=sentiment
206	    prompt_length=10
207	
208	    [task_1]
209	    task_name=intent_and_slot
210	    prompt_length=10
211	
212	    [task_2]
213	    task_name=squad
214	    prompt_length=16
215	    */
216	
217	    model_name_    = reader.Get("gpt", "model_name");
218	    head_num_      = reader.GetInteger("gpt", "head_num");
219	    size_per_head_ = reader.GetInteger("gpt", "size_per_head");
220	    inter_size_    = reader.GetInteger("gpt", "inter_size");
221	    num_layer_     = reader.GetInteger("gpt", "num_layer");
222	    vocab_size_    = reader.GetInteger("gpt", "vocab_size");
223	    /* Meta Opt Examples
224	    layernorm_eps=1e-5
225	    layernorm_type=pre_layernorm
226	    activation_type=Relu
227	    has_post_decoder_layernorm=0
228	    */
229	    gpt_variant_params_.layernorm_eps   = reader.GetFloat("gpt", "layernorm_eps", 1e-6f);
230	    gpt_variant_params_.layernorm_type  = ft::getLayerNormType(reader.Get("gpt", "layernorm_type", "pre_layernorm"));
231	    gpt_variant_params_.activation_type = ft::getActivationType(reader.Get("gpt", "activation_type", "Gelu"));
232	
233	    gpt_variant_params_.has_positional_encoding    = reader.GetBoolean("gpt", "has_positional_encoding", true);
234	    gpt_variant_params_.has_pre_decoder_layernorm  = reader.GetBoolean("gpt", "has_pre_decoder_layernorm", false);
235	    gpt_variant_params_.has_post_decoder_layernorm = reader.GetBoolean("gpt", "has_post_decoder_layernorm", true);
236	    gpt_variant_params_.use_attention_linear_bias  = reader.GetBoolean("gpt", "use_attention_linear_bias", false);
237	
238	    /* Megatron GPT Adapter Examples
239	    has_adapters=True
240	    adapter_inter_size=1024
241	    */
242	    gpt_variant_params_.has_adapters       = reader.GetBoolean("gpt", "has_adapters", false);
243	    gpt_variant_params_.adapter_inter_size = reader.GetInteger("gpt", "adapter_inter_size", inter_size_);
244	
245	    start_id_ = reader.GetInteger("gpt", "start_id");
246	    end_id_   = reader.GetInteger("gpt", "end_id");
247	
248	    max_seq_len_ = gpt_variant_params_.has_positional_encoding ?
249	                       reader.GetInteger("gpt", "max_pos_seq_len") :
250	                       reader.GetInteger("gpt", "max_pos_seq_len", FT_SEQ_LEN_MAX);
251	
252	    num_tasks_                = reader.GetInteger("gpt", "num_tasks", 0);
253	    prompt_learning_start_id_ = reader.GetInteger("gpt", "prompt_learning_start_id", end_id_ + 1);
254	    prompt_learning_type_ = static_cast<ft::PromptLearningType>(reader.GetInteger("gpt", "prompt_learning_type", 0));
255	
256	    for (int task_name_id = 0; task_name_id < num_tasks_; task_name_id++) {
257	        std::string config_task_name = "task_" + std::to_string(task_name_id);
258	        std::string task_name        = reader.Get(config_task_name, "task_name");
259	        const int   prompt_length    = reader.GetInteger(config_task_name, "prompt_length", 0);
260	        prompt_learning_table_pair_.insert({task_name, {task_name_id, prompt_length}});
261	    }
262	}
263	
264	template<typename T>
265	ParallelGptTritonModel<T>::ParallelGptTritonModel(size_t                                     max_seq_len,
266	                                                  size_t                                     head_num,
