292	    prompt_learning_type_(prompt_learning_type),
293	    prompt_learning_table_pair_(prompt_learning_table_pair),
294	    gpt_variant_params_(gpt_variant_params),
295	    tensor_para_size_(tensor_para_size),
296	    pipeline_para_size_(pipeline_para_size),
297	    shared_weights_(std::vector<std::shared_ptr<ft::ParallelGptWeight<T>>>(ft::getDeviceCount())),
298	    model_name_(model_name),
299	    model_dir_(model_dir),
300	    int8_mode_(int8_mode),
301	    enable_custom_all_reduce_(enable_custom_all_reduce)
302	{
303	}
304	
305	template<typename T>
306	std::unique_ptr<AbstractTransformerModelInstance> ParallelGptTritonModel<T>::createModelInstance(
307	    int                                                               device_id,
308	    int                                                               rank,
309	    cudaStream_t                                                      stream,
310	    std::pair<std::vector<ft::NcclParam>, std::vector<ft::NcclParam>> nccl_params,
311	    std::shared_ptr<ft::AbstractCustomComm>                           custom_all_reduce_comm)
312	{
313	    ft::check_cuda_error(cudaSetDevice(device_id));
314	    const int comms_rank = device_id % (tensor_para_size_ * pipeline_para_size_);
315	
316	    std::unique_ptr<ft::Allocator<ft::AllocatorType::CUDA>> allocator(
317	        new ft::Allocator<ft::AllocatorType::CUDA>(device_id));
318	
319	    allocator->setStream(stream);
320	
321	    cublasHandle_t   cublas_handle;
322	    cublasLtHandle_t cublaslt_handle;
323	
324	    cublasCreate(&cublas_handle);
325	    cublasLtCreate(&cublaslt_handle);
326	    cublasSetStream(cublas_handle, stream);
327	
328	    std::unique_ptr<ft::cublasAlgoMap>   cublas_algo_map(new ft::cublasAlgoMap("gemm_config.in"));
329	    std::unique_ptr<std::mutex>          cublas_wrapper_mutex(new std::mutex());
330	    std::unique_ptr<ft::cublasMMWrapper> cublas_wrapper(new ft::cublasMMWrapper(
331	        cublas_handle, cublaslt_handle, stream, cublas_algo_map.get(), cublas_wrapper_mutex.get(), allocator.get()));
332	
333	    std::unique_ptr<cudaDeviceProp> cuda_device_prop_ptr(new cudaDeviceProp);
334	    ft::check_cuda_error(cudaGetDeviceProperties(cuda_device_prop_ptr.get(), device_id));
335	
336	    if (std::is_same<T, half>::value) {
337	        cublas_wrapper->setGemmConfig(CUDA_R_16F, CUDA_R_16F, CUDA_R_16F, CUDA_R_32F);
338	    }
339	#ifdef ENABLE_BF16
340	    else if (std::is_same<T, __nv_bfloat16>::value) {
341	        cublas_wrapper->setBF16GemmConfig();
342	    }
343	#endif
344	    else if (std::is_same<T, float>::value) {
345	        cublas_wrapper->setFP32GemmConfig();
346	    }
347	
348	    ft::NcclParam tensor_para   = nccl_params.first[comms_rank];
349	    ft::NcclParam pipeline_para = nccl_params.second[comms_rank];
350	
351	    ft::AttentionType attention_type = ft::getAttentionType<T>(size_per_head_,
352	                                                               ft::getSMVersion(),
353	                                                               true,
354	                                                               0,                // gpt supports any-seq-length fmha
355	                                                               int8_mode_ != 2,  // is_fuse
356	                                                               false,            // with_relative_position_bias
357	                                                               true);            // causal_mask
358	
359	    auto gpt = std::make_unique<ft::ParallelGpt<T>>(
360	        ft::ParallelGpt<T>(0,  // max_batch_size, FT will adjust the buffer automatically.
361	                           0,  // max_seq_len, FT will adjust the buffer automatically.
362	                           0,  // max_input_len, FT will adjust the buffer automatically.
363	                           0,
364	                           head_num_,
365	                           size_per_head_,
366	                           inter_size_,
367	                           num_layer_,
368	                           0,   // expert_num
369	                           0,   // moe_k
370	                           {},  // moe_layer_index
371	                           vocab_size_,
372	                           start_id_,
373	                           end_id_,
374	                           prompt_learning_start_id_,  // p/prompt tuning virtual token start id
375	                           prompt_learning_type_,
376	                           gpt_variant_params_,
377	                           0.0f,  // beam_search_diversity_rate_,
378	                           1,     // top_k_,
379	                           0.0f,  // top_p_,
380	                           0,     // random seed, note that all gpus should use same seed
381	                           1.0f,  // temperature_,
382	                           0.0f,  // len_penalty_,
383	                           1.0f,  // repetition_penalty_,
384	                           tensor_para,
385	                           pipeline_para,
386	                           stream,
387	                           cublas_wrapper.get(),
388	                           allocator.get(),
389	                           false,
390	                           cuda_device_prop_ptr.get(),
391	                           attention_type,
392	                           false,
393	                           int8_mode_,
394	                           custom_all_reduce_comm,
395	                           enable_custom_all_reduce_));
396	
397	    return std::unique_ptr<ParallelGptTritonModelInstance<T>>(
398	        new ParallelGptTritonModelInstance<T>(std::move(gpt),
399	                                              shared_weights_[device_id],
400	                                              std::move(allocator),
401	                                              std::move(cublas_algo_map),
402	                                              std::move(cublas_wrapper_mutex),
403	                                              std::move(cublas_wrapper),
404	                                              std::move(cuda_device_prop_ptr)));
405	}
406	
407	template<typename T>
408	void ParallelGptTritonModel<T>::createSharedWeights(int device_id, int rank)
409	{
410	    ft::check_cuda_error(cudaSetDevice(device_id));
411	    const int tensor_para_rank   = rank % tensor_para_size_;
412	    const int pipeline_para_rank = rank / tensor_para_size_;
413	
414	    shared_weights_[device_id] = std::make_shared<ft::ParallelGptWeight<T>>(head_num_ * size_per_head_,
415	                                                                            inter_size_,
416	                                                                            vocab_size_,
417	                                                                            num_layer_,
418	                                                                            max_seq_len_,
419	                                                                            tensor_para_size_,
420	                                                                            tensor_para_rank,
421	                                                                            pipeline_para_size_,
422	                                                                            pipeline_para_rank,
423	                                                                            int8_mode_,
424	                                                                            prompt_learning_type_,
425	                                                                            prompt_learning_table_pair_,
426	                                                                            gpt_variant_params_);
427	    shared_weights_[device_id]->loadModel(model_dir_);
428	    return;
429	}
430	
