437	       << "\ninter_size: " << inter_size_ << "\nnum_layer: " << num_layer_ << "\nvocab_size: " << vocab_size_
438	       << "\nlayernorm_eps" << gpt_variant_params_.layernorm_eps << "\nlayernorm_type"
439	       << static_cast<int>(gpt_variant_params_.layernorm_type) << "\nactivation_type"
440	       << static_cast<int>(gpt_variant_params_.activation_type) << "\nhas_post_decoder_layernorm"
441	       << gpt_variant_params_.has_post_decoder_layernorm << "\nstart_id: " << start_id_ << "\nend_id: " << end_id_
442	       << "\ntensor_para_size: " << tensor_para_size_ << "\npipeline_para_size: " << pipeline_para_size_
443	       << "\nint8_mode: " << int8_mode_ << "\nenable_custom_all_reduce: " << enable_custom_all_reduce_
444	       << "\nmodel_name: " << model_name_ << "\nmodel_dir: " << model_dir_ << std::endl;
445	    return ss.str();
