64	template<typename T>
65	std::unordered_map<std::string, ft::Tensor> ParallelGptTritonModelInstance<T>::convert_inputs(
66	    std::shared_ptr<std::unordered_map<std::string, triton::Tensor>> input_tensors)
67	{
68	    const size_t request_batch_size = input_tensors->at("input_ids").shape[0];
69	    move_tensor_H2D(input_tensors->at("input_ids"), d_input_ids_, &allocator_);
70	    move_tensor_H2D(input_tensors->at("input_lengths"), d_input_lengths_, &allocator_);
71	
72	    h_total_output_lengths_ = (uint32_t*)std::realloc((void*)h_total_output_lengths_, request_batch_size * sizeof(uint32_t));
73	    const int input_data_len = input_tensors->at("input_ids").shape[1];
74	    const bool continue_interactive =
75	        input_tensors->count("START") && reinterpret_cast<const int32_t*>(input_tensors->at("START").data)[0] == 0;
76	    for (int i = 0; i < request_batch_size; ++i) {
77	        h_total_output_lengths_[i] = reinterpret_cast<const uint32_t*>(input_tensors->at("request_output_len").data)[i]
78	                                     + input_data_len + (continue_interactive ? gpt_->getStep() : 0);
79	    }
80	
81	    std::unordered_map<std::string, ft::Tensor> ft_input_tensors{
82	        {"input_ids", as_GPU_tensor(input_tensors->at("input_ids"), d_input_ids_)},
83	        {"input_lengths_h", as_CPU_tensor(input_tensors->at("input_lengths"))},
84	        {"input_lengths", as_GPU_tensor(input_tensors->at("input_lengths"), d_input_lengths_)},
85	        {"output_seq_len",
86	         ft::Tensor{ft::MEMORY_CPU,
87	                    ft::TYPE_UINT32,
88	                    {input_tensors->at("request_output_len").shape[0]},
89	                    h_total_output_lengths_}}};
90	
91	    if (input_tensors->count("request_prompt_embedding") && input_tensors->count("request_prompt_lengths")
92	        && input_tensors->count("request_prompt_type")) {
93	
94	        move_tensor_H2D(input_tensors->at("request_prompt_lengths"), d_request_prompt_lengths_, &allocator_);
95	        ft_input_tensors.insert(
96	            {"request_prompt_lengths_h", as_CPU_tensor(input_tensors->at("request_prompt_lengths"))});
97	        ft_input_tensors.insert(
98	            {"request_prompt_lengths",
99	             as_GPU_tensor(input_tensors->at("request_prompt_lengths"), d_request_prompt_lengths_)});
100	
101	        move_tensor_H2D(input_tensors->at("request_prompt_embedding"), d_request_prompt_embedding_, &allocator_);
102	        ft_input_tensors.insert(
103	            {"request_prompt_embedding",
104	             as_GPU_tensor(input_tensors->at("request_prompt_embedding"), d_request_prompt_embedding_)});
105	    }
106	
107	    if (input_tensors->find("bad_words_list") != input_tensors->end()) {
108	        move_tensor_H2D(input_tensors->at("bad_words_list"), d_input_bad_words_, &allocator_);
109	        ft_input_tensors.insert(
110	            {"bad_words_list", as_GPU_tensor(input_tensors->at("bad_words_list"), d_input_bad_words_)});
111	    }
112	
113	    if (input_tensors->find("stop_words_list") != input_tensors->end()) {
114	        move_tensor_H2D(input_tensors->at("stop_words_list"), d_input_stop_words_, &allocator_);
115	        ft_input_tensors.insert(
116	            {"stop_words_list", as_GPU_tensor(input_tensors->at("stop_words_list"), d_input_stop_words_)});
117	    }
118	
119	    if (input_tensors->find("top_p_decay") != input_tensors->end()) {
120	        move_tensor_H2D(input_tensors->at("top_p_decay"), d_top_p_decay_, &allocator_);
121	        ft_input_tensors.insert({"top_p_decay", as_GPU_tensor(input_tensors->at("top_p_decay"), d_top_p_decay_)});
122	    }
123	    if (input_tensors->find("top_p_min") != input_tensors->end()) {
124	        move_tensor_H2D(input_tensors->at("top_p_min"), d_top_p_min_, &allocator_);
125	        ft_input_tensors.insert({"top_p_min", as_GPU_tensor(input_tensors->at("top_p_min"), d_top_p_min_)});
126	    }
127	    if (input_tensors->find("top_p_reset_ids") != input_tensors->end()) {
128	        move_tensor_H2D(input_tensors->at("top_p_reset_ids"), d_top_p_reset_ids_, &allocator_);
129	        ft_input_tensors.insert(
130	            {"top_p_reset_ids", as_GPU_tensor(input_tensors->at("top_p_reset_ids"), d_top_p_reset_ids_)});
131	    }
132	
133	    for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
134	        if (t->first.find("input_ids") == std::string::npos && t->first.find("input_lengths") == std::string::npos
135	            && t->first.find("output_seq_len") == std::string::npos
136	            && t->first.find("request_prompt_embedding") == std::string::npos
137	            && t->first.find("request_prompt_lengths") == std::string::npos) {
138	            if (ft_input_tensors.count(t->first) == 0) {
139	                ft_input_tensors.insert({t->first, t->second.convertTritonTensorToFt()});
140	            }
141	        }
142	    }
143	
144	    return ft_input_tensors;
145	}
