147	template<typename T>
148	std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>
149	ParallelGptTritonModelInstance<T>::convert_outputs(const std::unordered_map<std::string, ft::Tensor>& output_tensors)
150	{
151	    std::unordered_map<std::string, triton::Tensor>* outputs_mapping =
152	        new std::unordered_map<std::string, triton::Tensor>();
153	
154	    for (auto it = output_tensors.begin(); it != output_tensors.end(); it++) {
155	        outputs_mapping->insert({it->first, triton::Tensor::convertFtTensorToTriton(it->second)});
156	    }
157	
158	    return std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>(outputs_mapping);
159	}
