161	template<typename T>
162	std::shared_ptr<std::unordered_map<std::string, triton::Tensor>> ParallelGptTritonModelInstance<T>::forward(
163	    std::shared_ptr<std::unordered_map<std::string, triton::Tensor>> input_tensors)
164	{
165	    FT_CHECK_WITH_INFO(input_tensors->at("input_ids").shape.size() == 2,
166	                       "input_tensors->at(\"input_ids\").shape.size() == 2");
167	    FT_CHECK_WITH_INFO(input_tensors->at("input_lengths").shape.size() == 1,
168	                       "input_tensors->at(\"input_lengths\").shape.size() == 1");
169	    const size_t request_batch_size     = input_tensors->at("input_ids").shape[0];
170	    size_t       max_request_output_len = (size_t)*std::max_element((int*)input_tensors->at("request_output_len").data,
171	                                                              (int*)input_tensors->at("request_output_len").data
172	                                                                  + input_tensors->at("request_output_len").shape[0]);
173	    size_t beam_width = input_tensors->count("beam_width") ? (size_t)(*(uint*)input_tensors->at("beam_width").data) : 1;
174	
175	    size_t total_length = max_request_output_len + input_tensors->at("input_ids").shape[1];
176	
177	    if (beam_width != 1 && beam_width != 2 && beam_width != 3 && beam_width != 4 && beam_width != 8 && beam_width != 16
178	        && beam_width != 32) {
179	        FT_LOG_WARNING("beam_width = %ld is invalid. Set it to 1 to use sampling by default.", beam_width);
180	        beam_width = 1;
181	    }
182	
183	    std::unordered_map<std::string, ft::Tensor> ft_input_tensors = convert_inputs(input_tensors);
184	
185	    const bool interactive_mode  = ft_input_tensors.count("START");
186	    const bool start_interactive = interactive_mode && ft_input_tensors["START"].getVal<int32_t>() == 1;
187	
188	    if (interactive_mode && !start_interactive) {
189	        ft_input_tensors.insert({"continue_gen", ft::Tensor{ft::MEMORY_CPU, ft::TYPE_BOOL, {1}, &interactive_mode}});
190	        total_length += gpt_->getStep();
191	    }
192	
193	    if (!interactive_mode || start_interactive) {
194	        size_t session_len = start_interactive ? ft_input_tensors.at("session_len").getVal<uint32_t>() : 0;
195	        allocateBuffer(request_batch_size,
196	                       beam_width,
197	                       start_interactive ? session_len : total_length,
198	                       start_interactive ? session_len : max_request_output_len);
199	    }
200	
201	    std::unordered_map<std::string, ft::Tensor> output_tensors = std::unordered_map<std::string, ft::Tensor>{
202	        {"output_ids",
203	         ft::Tensor{ft::MEMORY_GPU,
204	                    ft::TYPE_UINT32,
205	                    std::vector<size_t>{request_batch_size, beam_width, total_length},
206	                    d_output_ids_}},
207	        {"sequence_length",
208	         ft::Tensor{
209	             ft::MEMORY_GPU, ft::TYPE_INT32, std::vector<size_t>{request_batch_size, beam_width}, d_sequence_lengths_}},
210	        {"response_input_lengths",
211	         ft::Tensor{ft::MEMORY_GPU,
212	                    ft::TYPE_INT32,
213	                    std::vector<size_t>{request_batch_size, beam_width},
214	                    d_response_input_lengths_}},
215	        {"is_finished",
216	         ft::Tensor{
217	             ft::MEMORY_GPU, ft::TYPE_BOOL, std::vector<size_t>{request_batch_size, beam_width}, d_is_finished_}}};
218	
219	    if (input_tensors->count("is_return_log_probs") && *((bool*)input_tensors->at("is_return_log_probs").data)) {
220	        output_tensors.insert({"output_log_probs",
221	                               ft::Tensor{ft::MEMORY_GPU,
222	                                          ft::TYPE_FP32,
223	                                          std::vector<size_t>{request_batch_size, beam_width, max_request_output_len},
224	                                          d_output_log_probs_}});
225	        output_tensors.insert({"cum_log_probs",
226	                               ft::Tensor{ft::MEMORY_GPU,
227	                                          ft::TYPE_FP32,
228	                                          std::vector<size_t>{request_batch_size, beam_width},
229	                                          d_cum_log_probs_}});
230	    }
231	    if (input_tensors->count("is_return_context_embeddings")
232	        && *((bool*)input_tensors->at("is_return_context_embeddings").data)) {
233	        output_tensors.insert({"context_embeddings",
234	                               ft::Tensor{ft::MEMORY_GPU,
235	                                          ft::TYPE_FP32,
236	                                          std::vector<size_t>{request_batch_size, beam_width, gpt_->getHiddenUnits()},
237	                                          d_output_ctx_emb_}});
238	    }
239	
240	    try {
241	        if (stream_cb_ != nullptr) {
242	            gpt_->registerCallback(triton_stream_callback<T>, this);
243	        }
244	
245	        gpt_->forward(&output_tensors, &ft_input_tensors, gpt_weight_.get());
246	
247	        if (stream_cb_ != nullptr) {
248	            gpt_->unRegisterCallback();
249	        }
250	    }
251	    catch (...) {
252	        h_exception_ = std::current_exception();
253	        output_tensors.insert({"error_message", ft::Tensor{ft::MEMORY_CPU, ft::TYPE_BYTES, {1}, &h_exception_}});
254	    }
255	    return convert_outputs(output_tensors);
256	}
257	
258	template<typename T>
259	ParallelGptTritonModelInstance<T>::~ParallelGptTritonModelInstance()
260	{
261	    freeBuffer();
262	}
263	
264	template<typename T>
265	void ParallelGptTritonModelInstance<T>::allocateBuffer(const size_t request_batch_size,
266	                                                       const size_t beam_width,
267	                                                       const size_t total_output_len,
268	                                                       const size_t request_output_len)
269	{
270	    d_output_ids_ = (int*)(allocator_->reMalloc(
271	        d_output_ids_, sizeof(int) * request_batch_size * beam_width * total_output_len, false));
272	    d_sequence_lengths_ =
273	        (int*)(allocator_->reMalloc(d_sequence_lengths_, sizeof(int) * request_batch_size * beam_width, false));
274	    d_response_input_lengths_ =
275	        (int*)(allocator_->reMalloc(d_response_input_lengths_, sizeof(int) * request_batch_size * beam_width, false));
276	    d_output_log_probs_ = (float*)(allocator_->reMalloc(
277	        d_output_log_probs_, sizeof(float) * request_batch_size * beam_width * request_output_len, false));
278	    d_output_ctx_emb_   = (float*)(allocator_->reMalloc(
279	        d_output_ctx_emb_, sizeof(float) * request_batch_size * beam_width * gpt_->getHiddenUnits(), false));
280	    d_cum_log_probs_ =
281	        (float*)(allocator_->reMalloc(d_cum_log_probs_, sizeof(float) * request_batch_size * beam_width, false));
282	    d_is_finished_ =
283	        (bool*)(allocator_->reMalloc(d_is_finished_, sizeof(bool) * request_batch_size * beam_width, false));
284	}
285	
286	template<typename T>
287	void ParallelGptTritonModelInstance<T>::freeBuffer()
288	{
289	    allocator_->free((void**)(&d_output_ids_));
290	    allocator_->free((void**)(&d_sequence_lengths_));
291	    allocator_->free((void**)(&d_response_input_lengths_));
292	    allocator_->free((void**)(&d_output_log_probs_));
293	    allocator_->free((void**)(&d_output_ctx_emb_));
294	    allocator_->free((void**)(&d_cum_log_probs_));
295	    allocator_->free((void**)(&d_is_finished_));
296	    std::free(h_total_output_lengths_);
297	}
