183	        request_list[device_id]->insert(
184	            {"random_seed",
185	             triton::Tensor{triton::MEMORY_CPU, triton::TYPE_UINT64, std::vector<size_t>{1}, random_seed_ptr}});
186	        bool* is_return_log_probs_ptr = new bool(is_return_log_probs);
187	        pointer_record->push_back(is_return_log_probs_ptr);
188	        request_list[device_id]->insert(
189	            {"is_return_log_probs",
190	             triton::Tensor{triton::MEMORY_CPU, triton::TYPE_BOOL, std::vector<size_t>{1}, is_return_log_probs_ptr}});
191	        bool* is_return_context_cum_log_probs_ptr = new bool(is_return_context_cum_log_probs);
192	        pointer_record->push_back(is_return_context_cum_log_probs_ptr);
193	        request_list[device_id]->insert(
194	            {"is_return_context_cum_log_probs",
195	             triton::Tensor{
196	                 triton::MEMORY_CPU, triton::TYPE_BOOL, std::vector<size_t>{1}, is_return_context_cum_log_probs_ptr}});
197	        bool* is_return_context_embeddings_ptr = new bool(is_return_context_embeddings);
198	        pointer_record->push_back(is_return_context_embeddings_ptr);
199	        request_list[device_id]->insert(
200	            {"is_return_context_embeddings",
201	             triton::Tensor{
202	                 triton::MEMORY_CPU, triton::TYPE_BOOL, std::vector<size_t>{1}, is_return_context_embeddings_ptr}});
203	
204	        pointer_record->push_back(d_input_ids);
205	        pointer_record->push_back(d_input_lengths);
206	        pointer_record->push_back(request_output_len_ptr);
207	    }
208	
209	    return request_list;
210	}
