212	std::vector<std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>>
213	prepareRequest(std::string ini_name, const int node_id, const int gpu_count, std::vector<void*>* pointer_record)
214	{
215	    INIReader reader = INIReader(ini_name);
216	    if (reader.ParseError() < 0) {
217	        std::cout << "[ERROR] Can't load '" << ini_name << "'\n";
218	        ft::FT_CHECK(false);
219	    }
220	
221	    const size_t request_batch_size = reader.GetInteger("request", "request_batch_size");
222	    const size_t beam_width         = reader.GetInteger("ft_instance_hyperparameter", "beam_width");
223	    const size_t request_output_len = reader.GetInteger("request", "request_output_len");
224	    const int    top_k              = reader.GetInteger("ft_instance_hyperparameter", "top_k");
225	    const float  top_p              = reader.GetFloat("ft_instance_hyperparameter", "top_p");
226	    const float  temperature        = reader.GetFloat("ft_instance_hyperparameter", "temperature");
227	    const float  repetition_penalty = reader.GetFloat("ft_instance_hyperparameter", "repetition_penalty", 1.0f);
228	    const float  presence_penalty   = reader.GetFloat("ft_instance_hyperparameter", "presence_penalty", 0.0f);
229	    const int    min_length         = reader.GetInteger("ft_instance_hyperparameter", "min_length", 0);
230	    const float  len_penalty        = reader.GetFloat("ft_instance_hyperparameter", "len_penalty");
231	    const float  beam_search_diversity_rate =
232	        reader.GetFloat("ft_instance_hyperparameter", "beam_search_diversity_rate");
233	    const unsigned long long int random_seed         = 0;
234	    const bool                   is_return_log_probs = reader.GetBoolean("request", "return_log_probs", false);
235	    // Whether to include input contexts in computing the cumulative log probabilities.
236	    const bool is_return_context_cum_log_probs = reader.GetBoolean("request", "context_log_probs", false);
237	    const bool is_return_context_embeddings    = reader.GetBoolean("request", "context_embeddings", false);
238	    if (!is_return_log_probs && !is_return_context_cum_log_probs) {
239	        FT_LOG_WARNING("context_log_probs will be ignored since return_log_probs is disabled.");
240	    }
241	
242	    const int        end_id = 50256;
243	    std::vector<int> v_start_ids;
244	    std::vector<int> v_start_lengths;
245	
246	    size_t max_input_len = 0;
247	    ft::read_start_ids(request_batch_size,
248	                       &v_start_lengths,
249	                       &v_start_ids,
250	                       max_input_len,
251	                       end_id,
252	                       1,
253	                       "../examples/cpp/multi_gpu_gpt/start_ids.csv");
254	
255	    auto request_list = broadcastRequest(v_start_ids,
256	                                         v_start_lengths,
257	                                         node_id,
258	                                         gpu_count,
259	                                         beam_width,
260	                                         request_output_len,
261	                                         beam_search_diversity_rate,
262	                                         top_k,
263	                                         top_p,
264	                                         temperature,
265	                                         len_penalty,
266	                                         repetition_penalty,
267	                                         presence_penalty,
268	                                         min_length,
269	                                         random_seed,
270	                                         is_return_log_probs,
271	                                         is_return_context_cum_log_probs,
272	                                         is_return_context_embeddings,
273	                                         pointer_record);
274	    return request_list;
275	}
