277	int threadCreateModelInstances(std::shared_ptr<AbstractTransformerModel>                         model,
278	                               std::vector<std::unique_ptr<AbstractTransformerModelInstance>>*   model_instances,
279	                               const int                                                         device_id,
280	                               const int                                                         rank,
281	                               std::pair<std::vector<ft::NcclParam>, std::vector<ft::NcclParam>> nccl_comms,
282	                               std::shared_ptr<ft::AbstractCustomComm> custom_all_reduce_comm = nullptr)
283	{
284	    FT_LOG_INFO("rank = %d", rank);
285	    ft::check_cuda_error(cudaSetDevice(device_id));
286	    cudaStream_t stream;
287	    ft::check_cuda_error(cudaStreamCreate(&stream));
288	    model->createSharedWeights(device_id, rank);
289	    auto model_instance = model->createModelInstance(device_id, rank, stream, nccl_comms, custom_all_reduce_comm);
290	    model_instances->at(device_id) = std::move(model_instance);
291	    FT_LOG_INFO("model instance %d is created", device_id);
292	    ft::print_mem_usage();
293	    return 0;
294	}
