296	int threadForward(std::unique_ptr<AbstractTransformerModelInstance>*                model_instance,
297	                  std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>  request,
298	                  std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>* output_tensors,
299	                  const int                                                         device_id)
300	{
301	    ft::check_cuda_error(cudaSetDevice(device_id));
302	    *output_tensors = (*model_instance)->forward(request);
303	    return 0;
304	}
305	
306	int main(int argc, char* argv[])
307	{
308	    /*
309	        Prepare the nccl ids, node id, device id and world size
310	        by MPI or triton
311	    */
312	
313	    ft::mpi::initialize(&argc, &argv);
314	    int node_id  = ft::mpi::getCommWorldRank();
315	    int node_num = ft::mpi::getCommWorldSize();
316	
317	    // Note: Only supports that all nodes have same gpu count
318	    const int   gpu_count  = ft::getDeviceCount();
319	    const int   world_size = node_num * gpu_count;
320	    std::string ini_name   = argc >= 2 ? std::string(argv[1]) : "../examples/cpp/multi_gpu_gpt/gpt_config.ini";
321	
322	    // step 1: Create model
323	    std::shared_ptr<AbstractTransformerModel> model              = AbstractTransformerModel::createGptModel(ini_name);
324	    int                                       tensor_para_size   = model->getTensorParaSize();
325	    int                                       pipeline_para_size = model->getPipelineParaSize();
326	    FT_CHECK_WITH_INFO(world_size == (tensor_para_size * pipeline_para_size),
327	                       ft::fmtstr("World Size (%d) != Tensor Parallel Size (%d) * Pipeline Parallel Size (%d).",
328	                                  world_size,
329	                                  tensor_para_size,
330	                                  pipeline_para_size));
331	
332	    std::cout << model->toString();
333	
334	    // step 2: Initialize the NCCL
335	    std::pair<std::vector<ft::NcclParam>, std::vector<ft::NcclParam>> nccl_comms = model->createNcclParams(node_id);
336	    cudaDeviceSynchronize();
337	
338	    // Optional Step: create custom all reduce comm
339	    std::vector<std::shared_ptr<ft::AbstractCustomComm>> custom_all_reduce_comms;
340	    model->createCustomComms(&custom_all_reduce_comms, world_size);
341	
342	    // step 3: Create model instances
343	    std::vector<std::unique_ptr<AbstractTransformerModelInstance>> model_instances((size_t)gpu_count);
344	    std::vector<std::thread>                                       threads;
345	
346	    threads.clear();
347	
348	    for (int device_id = 0; device_id < gpu_count; device_id++) {
349	        const int rank = node_id * gpu_count + device_id;
350	        threads.push_back(std::thread(threadCreateModelInstances,
351	                                      model,
352	                                      &model_instances,
353	                                      device_id,
354	                                      rank,
355	                                      nccl_comms,
356	                                      custom_all_reduce_comms[rank]));
357	    }
358	    for (auto& t : threads) {
359	        t.join();
360	    }
361	
362	    // step 4: prepare request
363	    std::vector<void*> pointer_record;  // Used to prevent the pointers are release after leaving functions
364	    std::vector<std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>> request_list =
365	        prepareRequest(ini_name, node_id, gpu_count, &pointer_record);
366	    FT_LOG_INFO("request is created");
367	
368	    // step 5: Forward
369	    std::vector<std::shared_ptr<std::unordered_map<std::string, triton::Tensor>>> output_tensors_lists(
370	        (size_t)gpu_count);
371	    for (int i = 0; i < 2; i++) {
372	        threads.clear();
373	        for (int device_id = 0; device_id < gpu_count; device_id++) {
374	            threads.push_back(std::thread(threadForward,
375	                                          &model_instances[device_id],
376	                                          request_list[device_id],
377	                                          &output_tensors_lists[device_id],
378	                                          device_id));
379	        }
380	        for (auto& t : threads) {
381	            t.join();
382	        }
383	    }
384	    FT_LOG_INFO("forward is completed.");
385	
386	    const int* d_output_ids = (const int*)output_tensors_lists[0].get()->at("output_ids").data;
387	    const int  batch_size   = output_tensors_lists[0].get()->at("output_ids").shape[0];
388	    const int  beam_width   = output_tensors_lists[0].get()->at("output_ids").shape[1];
389	    const int  seq_len      = output_tensors_lists[0].get()->at("output_ids").shape[2];
390	    // step 6: check results
391	    if (node_id == 0) {
392	
393	        std::string fName   = "out";
394	        auto        outFile = std::ofstream(fName, std::ios::out);
395	        if (!outFile.is_open()) {
396	            FT_LOG_WARNING("Cannot write results into output file %s", fName.c_str());
397	        }
398	        else {
399	            size_t outCount = batch_size * beam_width * seq_len;
400	            int*   hBuf     = new int[outCount];
401	            ft::cudaD2Hcpy(hBuf, d_output_ids, outCount);
402	
403	            {
404	                std::cout << "Writing " << outCount << " elements\n";
405	                int zeroCount = 0;
406	                for (size_t i = 0; i < outCount; i++) {
407	                    if (hBuf[i] == int(0)) {
408	                        zeroCount++;
409	                    }
410	                    outFile << hBuf[i] << " ";
411	                    if ((i + 1) % (seq_len) == 0) {
412	                        outFile << std::endl;
413	                    }
414	
415	                    if (i < 10) {
416	                        printf("%5d ", hBuf[i]);
417	                    }
418	                    if ((i + 1) % (seq_len) == 0 && i < 10) {
419	                        std::cout << std::endl;
420	                    }
421	                }
422	                std::cout << std::endl << "zeroCount = " << zeroCount << std::endl;
423	            }
424	            delete[] hBuf;
425	        }
426	    }
427	
428	    // test time
429	    struct timeval start, end;
430	    ft::mpi::barrier();
431	    cudaDeviceSynchronize();
432	    gettimeofday(&start, NULL);
433	
434	    const int ite = 1;
435	    for (int i = 0; i < ite; i++) {
436	        threads.clear();
437	        for (int device_id = 0; device_id < gpu_count; device_id++) {
438	            threads.push_back(std::thread(threadForward,
439	                                          &model_instances[device_id],
440	                                          request_list[device_id],
441	                                          &output_tensors_lists[device_id],
442	                                          device_id));
443	        }
444	        for (auto& t : threads) {
445	            t.join();
446	        }
447	    }
448	
449	    cudaDeviceSynchronize();
450	    ft::mpi::barrier();
451	
452	    gettimeofday(&end, NULL);
453	
454	    FT_LOG_INFO("batch_size %d beam_width %d seq_len %d"
455	                " FT-CPP-GPT-Triton-time %.2f ms",
456	                batch_size,
457	                beam_width,
458	                seq_len,
459	                ((end.tv_sec - start.tv_sec) * 1000 + (end.tv_usec - start.tv_usec) * 0.001) / ite);
460	
461	    ft::mpi::finalize();
462	    return 0;
463	}
